import{c as e,Q as a,j as i,m as l}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"致枢机主教阿利多西的推","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/47-致枢机主教阿利多西的推.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/47-致枢机主教阿利多西的推.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/47-致枢机主教阿利多西的推.md"};function t(r,p,o,_,m,d){return a(),i("div",null,[...p[0]||(p[0]=[l('<h1 id="致枢机主教阿利多西的推" tabindex="-1">致枢机主教阿利多西的推 <a class="header-anchor" href="#致枢机主教阿利多西的推" aria-label="Permalink to &quot;致枢机主教阿利多西的推&quot;">​</a></h1><p>致枢机主教阿利多西的推荐信</p><p>在基督天父里至为尊贵并最受人尊敬的阁下、弗朗切斯科大人、神圣 罗马大公教会帕维亚枢机主教③、我们特殊的朋友： 教皇陛下几天前派出教廷书记官梅里诺大人向我们通报了一些事情； 那些事情相当重要，使我们愿意当面口头向陛下做出回答；基于这个原 因，我们城邦的公民和国务秘书尼科洛 · 马基雅维利将接受我们城邦自由 与和平十人委员会的委派，出使教皇陛下；为此，我们请求至为尊贵的阁 下能够为他提供拜会教皇陛下所需的帮助，此外，请相信他以我们的名义 所说的一切；祝一切顺利。 发自佛罗伦萨市政宫，1506年8月25日 马尔切洛</p><p>①英译本未收入，由王永忠依据贝尔泰利编校本译出。 ——编者注 ②英译本未收入，由王永忠依据贝尔泰利编校本译出。 ——编者注 ③阿利多西曾经是帕维亚的主教，自1503年11月成为枢机主教。 — 贝尔泰利编校本注</p><p>Opere complete di Niccolò Machiavelli</p><p>第二次出使罗马教廷</p><p>诸位大人钧鉴： 我昨天到达了内皮，而教皇和教廷也在同一天到达。由于教皇陛下是 在前一天才离开罗马的，他没有出席昨晚的任何活动，因此我没有见到 他。但今天早上，我在他早餐后立即晋见了他。在他从餐桌上起身之前， 他与我有过交谈。在场的还有沃尔泰拉和帕维亚主教①,以及刚从佛罗伦 萨赶来的加布里埃洛大人。为了使诸位大人可以同时得知我说的话和对我 的答复，我将把两者一起逐字呈报如下： “教皇大人陛下，您知道我杰出的执政团是如何地愿为圣座献身，且 为了巩固增进其荣耀是如何坚定无畏地将自己置于危险之中的。对于您， 这种持久的忠诚则又会加倍，因为即使在您获得如今的高位之前，他们就 视您为我们共和国的父亲和保护者了。因此，他们无疑会渴望增进陛下的 尊荣与权力，因为随着这种增进而加强的，是我们对于从陛下那里获得为 吾国福利所需之物的希望。至于陛下通过自己使节告知他们的计划，他们 对此非常满意，对您的赞扬无以复加，只能称其为至善且圣洁，真正配得 上陛下的神圣和良善。的确，由于很多一般和个别的处境与重要的考虑， 使得他们一度有所迟疑，难以决断。这是因为他们知道斐迪南国王将要前 往那不勒斯。考虑到有些人会对此不满，可能会引发骚乱。他们了解到， 皇帝正带着他的军队驻扎在威尼斯边境，而威尼斯政府则将它的人马派 到了弗留利，在那里任命了2位督政官②,并给予了他们很大的权力和权 威。”(我之所以说这些，是因为我昨天从一个极其值得信赖的人那里听 说，这个消息乃是真实的。)“现在，皇帝的这次入侵，”我接着说道， “如果继续推进下去则兹事体大，因为这可能在意大利造成很大的麻烦。 因此，值得对此进行严肃的考虑。至于我执政团的诸位大人，则还在处理</p><p>①此人是里奥城堡的弗朗切斯科先生，任帕维亚主教、枢机主教等职。 ——英译本注 ②督政官( provveditore), 威尼斯共和国的地方行政首长。——中译者注</p><p>第二次出使罗马教廷 与比萨的战争。这场战争仍像以往一样棘手，甚至是更为棘手，因为比 萨人日益显得胆大妄为。我执政团的诸位大人今年还遣散了约200名重骑 兵，只留下了刚刚能够满足防务所需的人马，且除了马科 · 安东尼奥外， 就没有其他的指挥官了。要是还让他们为之效劳的话，就可能会对他们造 成严重的损害。他们听说威尼斯人对此计划相当不满，而后者在罗马的大 使也证实了这一点。我执政团的诸位大人还注意到了另外一件事，请陛下 容我提一句。在他们看来，对教会事务的管理与对其他邦国事务的管理并 不协调。他们发现，在教会辖区内的城镇，有人从一个门离开后，又从另 一个门重新进来了。例如，在弗利的莫拉蒂尼就赶走了那些被陛下安排在 那里的人。不仅如此，我们没有看见任何迹象表明法国人正在行动。这就 毁掉了我们对陛下在那里所公开承诺之言的信心。不过，尽管有这些忧虑 (陛下想必能完全理解其重要性),我执政团的诸位大人还是决定，坚持 完成向此神圣事业伸出援手的目标。而且，在您的使节向我们说过的援助 落实后，我们将去做一切令您满意的事情。我相信，除了向您读一下我执 政团的诸位大人给我的敕令外，无法更好地表达我执政团的诸位大人的愿 望和意图，也无法更有效地坦诚事实。因此，我请求您允许我朗读这一敕 令。”说完后，我就从口袋里拿出敕令，逐字逐句地朗读了出来。 教皇陛下认真且愉快地倾听了我的讲话和敕令，并随后亲切地进行了 简要的回答： “在认真考虑了你所说所读之后，我感觉你执政团的诸位大 人似乎害怕三件事：首先，怕法国国王不提供援手；其次，怕他本人对此 事不热心；最后，怕他与乔瓦尼 ·本蒂沃利奥大人达成协议，允许他留在 博洛尼亚，甚至在把他驱赶走之后，或许还会再让他回来。对于这三件事 中的第一件，”教皇陛下说道，“我的回答是，为了向你充分证明法王的 善意，我会让你看看他的亲笔信。不用看其他证据，光是他的签名就足以 证明这一点了。”然后，他唤来了前西斯特隆主教德 · 阿伊克斯大人，让 他拿出他从法国带来的敕令，给我看了国王的亲笔签名，并亲口给我读了 两段关于处理博洛尼亚事务的内容。第一段话鼓励教皇实施这项反对博洛</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>第二次出使罗马教廷 尼亚的事业，并向他提供400至500人的长矛手。这些人或是由德 · 阿莱格 里大人带领，或是由曼托瓦侯爵带领，或是由2人共同带领，全看教皇的 意见而定。国王在第二段话中说，他和乔瓦尼大人之间的协定对他无关紧 要，因为根据那一协定，他的义务只是在乔瓦尼大人自己的领地上保护后 者，而不是在教会领地上保护他。他还建议教皇的行动“快一些，再快一 些”——这是他的原话。他同时还建议说，教皇应该使用一切手段，以 避免激起正在法恩扎的威尼斯人的嫉妒心。在此之后，教皇陛下还为我朗 读了法王的其他来信，上面都有其亲笔签名。在西斯特隆带来的一封信 上，日期标注是5月份。另有一封这个月的来信，是带给米兰大团长的， 上面命令他准备好400到500长矛手，随时听候德 · 阿伊克斯大人召唤，或 听候其他被任命去服务教皇的人召唤。在朗读了国王的这些段落和信件之 后，教皇陛下说，他不知道还能拿什么来向我证明国王的善意，而这些也 该令诸位大人满意了。至于他自己在此事上的冷淡，他说他正在亲自动身 前往。他还说，除了亲临指导此项计划以外，他不相信别的方法能表现出 更多的热心和诚意。还有第三点，即让乔瓦尼大人留在博洛尼亚，或是在 驱赶他后又允许他回来。教皇陛下说，在任何情况下，他都不会让乔瓦尼 大人留在那里，而后者保留私人公民身份的企图也是愚蠢的，因为他肯定 不会允许他保留任何其他身份。而一旦解决了乔瓦尼大人，他就希望能把 事情定下来，以使乔瓦尼大人在教皇自己的有生之年都无法回来。但关于 后继的教皇对此可能做什么,他说他就不知道了。教皇陛下总结说，我的 陪伴会使他欣喜，他也感谢诸位大人目前为止向他作的承诺。他还能够肯 定，由于在你们所怀疑的事情上，法王已经表达了诚意，所以你们必能完 成余下的承诺。他还说数日内就会让我知道进展，等等。 我不想把我的答复写下来烦扰诸位大人，只想向你们保证，我在各方 面都严格地遵循了你们的敕令。我也没有忘记告诉你们，在会面的过程 中，教皇陛下向沃尔泰拉和帕维亚主教耳语了几句，然后转过头来对我 说 ： “我对你说过，我希望给你执政团的诸位大人一些丰厚的好处，但</p><p>第二次出使罗马教廷 我现在无法对此做出承诺，因为我无法履行。 一旦我有能力去做，我就 会向你们做出承诺，并绝不食言。我一定会去做的。”于是，我便从教皇 的脚下起身，并同德 · 阿伊克斯领主(前面说过他也在场)一同退席。这 位德 · 阿伊克斯领主对我说，他在法国为了劝诱国王同意这一计划，经历 了很大的困难，而这都是因为国王不相信此事能够做成。但是，现在眼见 着事情真的开始启动了，国王就有了双倍的愿望去服侍教皇。我回复道， 几天以前，一位来自米兰的信使到达了佛罗伦萨，激起了巨大的震惊。他 是由大团长所派来的，为的是鼓励乔瓦尼大人，向他保证国王不会让他失 望，等等。他回答说，我不应为此而感到震惊，因为大团长之所以派此人 前来，要么是自愿前来，合乎法国习俗，在按礼数行事，要么是国王感觉 事情在罗马毫无进展，什么都没有启动，这才同意派人前去。他自己对此 则不那么惊讶，因为当他在宫廷陪伴国王时，在与教皇的条约最终签署 后，国王亲自大声安抚一位来自博洛尼亚的信使，让他放松心情，不要害 怕，因为教皇之所以要求他给予支持，只是为了对付佩鲁贾，而如果教皇 是为其他任何目的而来的，他就不会去为教皇效劳。 在22点时，我随同教皇去视察当地的壮观堡垒。教皇陛下在看见我 后，把我叫到一旁，把他早上回复我时所做的保证重申了一遍。他说，对 于最能让诸位大人疑虑的那些问题，他已经最为妥善地安排和解决好了。 然后，他又一字不差地重复了他早上说过的那些话。当我用敕令上的话回 答他说“我们的军队不会是最后到达的”时，教皇陛下说，他有三类人马 可供使用：他自己的人马，法国的人马，以及我们的人马。在他自己这 边，他有400名薪酬丰厚的重骑兵。他会将他们先行派出，并期待另有100 名他已付过钱的雇佣兵从那不勒斯王国赶来。他还会掌握詹保罗 · 巴廖尼 的军队。这支军队或者将由他自己指挥，或者由他认为最合适的人指挥。 他手里还有充足的步兵部队。所以，当这些军队全部集结起来时，既然我 们不想让自己成为最后到来的人，我们的人马就可以前来填补他们的空 缺。教皇希望我将所有这些都写信告知诸位大人，他则会每天通知我可能</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>第二次出使罗马教廷 我以得体的礼节进行了回复，但所说的完全限于一般性的套话。由于 是头一天到这里，除了教皇陛下的话以外，我无法向诸位大人汇报更多 的东西。但是，从他最后所说的话里，我猜他很快就会要求你们的军队 开拔，哪怕法国国王的军队还没有动身。他似乎在暗示，除非在必要的情 况下，否则他不会去利用法王的军队。这既是因为那些军队会带来巨大的花 销，也是为了避免招致法国的敌意(这种对他的敌意已经是非常强烈了)。 教皇陛下的雇佣兵队长之一拉马佐托也在这里，并承诺说，当地的山 民非常爱戴他，所以他将会动员他们中的三分之二来支持教皇。教皇身边 总是有六七位枢机主教陪伴。他似乎很喜欢这个样子。这或许是为了征求 他们的意见，或者是为了其他原因。其他的枢机主教被分散在周围的地 方，但在教皇去维特波时，他们会全都陪在他身边。 根据我所听说到的，教皇陛下的行程将会是这样：他明天会留在这 里，周日前去维特波，并在那里停留3天。从那里出发后，他将前去奥尔 维耶托，然后是皮耶加约，然后是佩鲁贾。他在这些地方停留的时间或长 或短。但我们还不知道他意欲以何种方式解决那里的事务，也不知道他和 詹保罗做了什么安排。据说，后者将会前来会见教皇，甚至会在教皇离开 维特波之前就过来。离开佩鲁贾后，教皇将会前往乌尔比诺，并准备在那 里招募4000步兵。据权威人士声称，在到达切塞纳之前，费拉拉公爵和曼 托瓦侯爵将会前来会见他。 我身边发生的其他事情就没有什么可写的了。敬请诸位大人多多关</p><p>第二次出使罗马教廷 照 ，再会并祝好运。</p><p>卡斯特利亚纳城，1506年8月28日 仆尼科洛 · 马基雅维利，国务秘书 附注：我忘了告诉诸位大人，教皇曾经说过(在全体枢机主教在场时 也这么说),那不勒斯和阿拉贡的国王斐迪南前些日子曾传话过来，命令 他在罗马的大使不要离开该城，因为国王不日将抵达邻近的某个港口，并 想在那里会见他。但他之后又写信过来，要求大使前去教廷所到达之地， 并找到教皇陛下。于是，大使便带着国王的指令前往博洛尼亚。就像教皇 所希望的那样，大使告诉乔瓦尼大人和他的政府人员说，如果他们不向教 会屈服的话，就等于把国王看作他们的敌人和最严厉的追查者。国王愿意为 此而亲自前来降服他们。反之，如果他们愿意和教皇达成协议，国王则希望 充当该协议的调停人和保证人，并将向乔瓦尼大人承诺，无论是他、他的孩 子，还是他的祖传家产，都不会受到任何方式的侵扰。再次说再会!</p><p>日期如信中 仆尼科洛</p><p>信件2</p><p>诸位大人钧鉴： 我于28日在卡斯特利亚纳城向诸位大人所写的信，与此信一起寄上。 前一封信之所以没有更早送出，是因为我不想寄希望于偶然。那是一封很 重要的信，而且不是用密码写成的(因为我身边没有带着密码)。我认 为今晚必须将它寄出去，于是决定由特使来递送此信。他将在晚上2点出 发，并承诺于明天24点到达佛罗伦萨。我已经付给了他80卡利尼，请诸位</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>第二次出使罗马教廷 大人将同样数目的钱支付给大使比亚焦。 教皇今天大张旗鼓地进入了维特波，而且在接下来的行程中，还会继 续同样的排场。从那不勒斯方面，我们得知那不勒斯人正准备以尽可能隆 重的场面来迎接国王。孔萨尔沃将会前去拜见他并致以敬意。我们还听 说，威尼斯人正在罗马涅聚集起1000步兵。有人说，他们的目标是弗留 利，有些人则说他们是为了警戒法恩扎，让那里的居民不要在教皇经过时 做出蠢事。 敬请诸位大人多多关照。</p><p>维特波，1506年8月30日 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件3</p><p>诸位大人钧鉴： 我昨天向诸位大人写了一封信，并将其与28日的信件一起交给了信使 寄出。在信中，我完整地记录了我在抵达后立即与教皇进行的谈话。自那 之后，教皇陛下没有和我做进一步的交流，我也没有尝试去拜见他。目前 唯一的消息是威尼斯大使晋见教皇陛下，解释了他的执政团在罗马涅征兵 一事。大使说，根据他们的习俗，当邻居们武装起来时，他们自己也要武 装起来。威尼斯人散布消息说，神圣罗马帝国皇帝已经来到了弗留利的边 境，但据来自费拉拉的信件说，这纯属一派胡言。人们相信，若来信属实 的话，大使就是在奉他执政团的命令散布谣言，为的是让教皇难堪，并在 其计划刚刚开始时，就用这样的消息来给他泼一盆冷水。 曼托瓦侯爵的一个代理人今天经由驿站来到了这里。他此行的目的还 不完全清楚，但人们说，侯爵派他来是为了致以歉意，因为他无法像之前</p><p>第二次出使罗马教廷 承诺的那样前来拜见教皇陛下。如果这是真的，有些人就会积极地推论 说，也许法国国王正在拖延时间。其他人则会相信，这只不过是因为侯爵 一方的轻率易变。 一旦我得知此事的真相，我会马上告知诸位大人。我已 经拜访了法王在这里的大使吉梅尔大人，以诸位大人仆人的身份，用我认 为合适的方式向他表达了我的敬意。他也以最为得体的方式答复了我。在 我们的谈话过程中，他向我保证说，国王陛下向教皇提供了德 · 阿莱格里 大人麾下的500名雇佣兵，以供其随时驱使。</p>',25)])])}const n=e(c,[["render",t]]);export{h as __pageData,n as default};
